# Resource names from environment variables (set during deployment)
DYNAMODB_ORDERS_TABLE = os.environ.get('ORDERS_TABLE', '')
DYNAMODB_USERS_TABLE = os.environ.get('USERS_TABLE', '')
DYNAMODB_INVENTORY_TABLE = os.environ.get('INVENTORY_TABLE', '')
S3_DATA_BUCKET = os.environ.get('DATA_BUCKET', '')
SNS_ORDER_TOPIC_ARN = os.environ.get('ORDER_NOTIFICATION_TOPIC_ARN', '')
SQS_ORDER_QUEUE_URL = os.environ.get('ORDER_PROCESSING_QUEUE_URL', '')
ALLOWED_S3_PREFIXES = frozenset(
    os.environ.get('ALLOWED_S3_PREFIXES', 'data/,uploads/,processed/').split(',')
)

# Validate required environment variables at cold start
_REQUIRED_ENV_VARS = [
    'ORDERS_TABLE', 'USERS_TABLE', 'INVENTORY_TABLE',
    'DATA_BUCKET', 'ORDER_NOTIFICATION_TOPIC_ARN', 'ORDER_PROCESSING_QUEUE_URL'
]

_missing_vars = [var for var in _REQUIRED_ENV_VARS if not os.environ.get(var)]
if _missing_vars:
    logger.error(f"Missing required environment variables: {_missing_vars}")


def _get_dynamodb_client():
    """Create a DynamoDB resource with consistent configuration."""
    return boto3.resource('dynamodb')


def _get_s3_client():
    """Create an S3 client."""
    return boto3.client('s3')


def _get_sns_client():
    """Create an SNS client."""
    return boto3.client('sns')


def _get_sqs_client():
    """Create an SQS client."""
    return boto3.client('sqs')


def _validate_s3_key(key):
    """
    Validate that the S3 key is within allowed prefixes to prevent
    path traversal or access to unauthorized paths.
    """
    if not key or not isinstance(key, str):
        raise ValueError("S3 key must be a non-empty string")

    # Normalize the key to prevent path traversal
    normalized_key = os.path.normpath(key).replace('\\', '/')
    if normalized_key.startswith('/') or '..' in normalized_key:
        raise ValueError(f"Invalid S3 key (path traversal detected): {key}")

    # Check that the key starts with an allowed prefix
    if not any(normalized_key.startswith(prefix) for prefix in ALLOWED_S3_PREFIXES):
        raise ValueError(
            f"S3 key '{key}' is not within allowed prefixes: {ALLOWED_S3_PREFIXES}"
        )

    return normalized_key


def _validate_table_name(table_name):
    """Validate that the requested table is one of our allowed tables."""
    allowed_tables = {DYNAMODB_ORDERS_TABLE, DYNAMODB_USERS_TABLE, DYNAMODB_INVENTORY_TABLE}
    if table_name not in allowed_tables:
        raise ValueError(f"Table '{table_name}' is not in the allowed tables list")
    return table_name


def _sanitize_input(value, field_name, max_length=256):
    """Basic input sanitization for string values."""
    if not isinstance(value, str):
        raise ValueError(f"Field '{field_name}' must be a string")
    if len(value) > max_length:
        raise ValueError(f"Field '{field_name}' exceeds maximum length of {max_length}")
    # Strip control characters
    sanitized = ''.join(c for c in value if c.isprintable() or c in ('\n', '\t'))
    return sanitized.strip()


def process_order(order_data):
    """
    Process an order: store in DynamoDB, upload receipt to S3,
    send notification via SNS, and queue for further processing via SQS.
    """
    if not order_data or not isinstance(order_data, dict):
        raise ValueError("Order data must be a non-empty dictionary")

    # Validate and sanitize required fields
    order_id = _sanitize_input(order_data.get('order_id', ''), 'order_id', max_length=64)
    customer_id = _sanitize_input(order_data.get('customer_id', ''), 'customer_id', max_length=64)
    
    if not order_id or not customer_id:
        raise ValueError("order_id and customer_id are required")

    items = order_data.get('items', [])
    if not isinstance(items, list) or not items:
        raise ValueError("items must be a non-empty list")

    # Validate items
    validated_items = []
    for item in items:
        if not isinstance(item, dict):
            raise ValueError("Each item must be a dictionary")
        validated_item = {
            'product_id': _sanitize_input(item.get('product_id', ''), 'product_id', max_length=64),
            'quantity': int(item.get('quantity', 0)),
            'price': str(item.get('price', '0'))
        }
        if validated_item['quantity'] <= 0:
            raise ValueError("Item quantity must be positive")
        validated_items.append(validated_item)

    total_amount = sum(float(item['price']) * item['quantity'] for item in validated_items)

    results = {
        'order_id': order_id,
        'status': 'processing',
        'steps_completed': []
    }

    # Step 1: Store order in DynamoDB
    try:
        dynamodb = _get_dynamodb_client()
        table = dynamodb.Table(_validate_table_name(DYNAMODB_ORDERS_TABLE))
        table.put_item(
            Item={
                'order_id': order_id,
                'customer_id': customer_id,
                'items': validated_items,
                'total_amount': str(total_amount),
                'status': 'received'
            },
            ConditionExpression='attribute_not_exists(order_id)'
        )
        results['steps_completed'].append('dynamodb_store')
        logger.info(f"Order {order_id} stored in DynamoDB")
    except ClientError as e:
        if e.response['Error']['Code'] == 'ConditionalCheckFailedException':
            logger.warning(f"Order {order_id} already exists (idempotency check)")
            results['steps_completed'].append('dynamodb_store_idempotent')
        else:
            logger.error(f"DynamoDB error for order {order_id}: {e}")
            raise

    # Step 2: Upload order receipt to S3
    try:
        s3_client = _get_s3_client()
        s3_key = _validate_s3_key(f"processed/orders/{order_id}/receipt.json")
        receipt_data = json.dumps({
            'order_id': order_id,
            'customer_id': customer_id,
            'total_amount': str(total_amount),
            'item_count': len(validated_items)
        })
        s3_client.put_object(
            Bucket=S3_DATA_BUCKET,
            Key=s3_key,
            Body=receipt_data,
            ContentType='application/json',
            ServerSideEncryption='aws:kms'
        )
        results['steps_completed'].append('s3_receipt_upload')
        logger.info(f"Receipt for order {order_id} uploaded to S3")
    except ClientError as e:
        logger.error(f"S3 error for order {order_id}: {e}")
        raise

    # Step 3: Send notification via SNS
    try:
        sns_client = _get_sns_client()
        # Only publish to the configured topic ARN - no user-controlled topic
        sns_client.publish(
            TopicArn=SNS_ORDER_TOPIC_ARN,
            Subject=f"New Order Received: {order_id}",
            Message=json.dumps({
                'order_id': order_id,
                'customer_id': customer_id,
                'total_amount': str(total_amount),
                'event_type': 'ORDER_RECEIVED'
            }),
            MessageAttributes={
                'event_type': {
                    'DataType': 'String',
                    'StringValue': 'ORDER_RECEIVED'
                }
            }
        )
        results['steps_completed'].append('sns_notification')
        logger.info(f"SNS notification sent for order {order_id}")
    except ClientError as e:
        logger.error(f"SNS error for order {order_id}: {e}")
        raise

    # Step 4: Queue for further processing via SQS
    try:
        sqs_client = _get_sqs_client()
        sqs_client.send_message(
            QueueUrl=SQS_ORDER_QUEUE_URL,
            MessageBody=json.dumps({
                'order_id': order_id,
                'customer_id': customer_id,
                'action': 'PROCESS_ORDER',
                'total_amount': str(total_amount)
            }),
            MessageGroupId=customer_id if '.fifo' in SQS_ORDER_QUEUE_URL else None,
            MessageDeduplicationId=order_id if '.fifo' in SQS_ORDER_QUEUE_URL else None
        ) if '.fifo' in SQS_ORDER_QUEUE_URL else sqs_client.send_message(
            QueueUrl=SQS_ORDER_QUEUE_URL,
            MessageBody=json.dumps({
                'order_id': order_id,
                'customer_id': customer_id,
                'action': 'PROCESS_ORDER',
                'total_amount': str(total_amount)
            })
        )
        results['steps_completed'].append('sqs_queue')
        logger.info(f"Order {order_id} queued for processing")
    except ClientError as e:
        logger.error(f"SQS error for order {order_id}: {e}")
        raise

    results['status'] = 'completed'
    return results


def get_order(order_id):
    """Retrieve an order from DynamoDB."""
    order_id = _sanitize_input(order_id, 'order_id', max_length=64)
    
    dynamodb = _get_dynamodb_client()
    table = dynamodb.Table(_validate_table_name(DYNAMODB_ORDERS_TABLE))
    
    try:
        response = table.get_item(Key={'order_id': order_id})
        item = response.get('Item')
        if not item:
            return None
        return item
    except ClientError as e:
        logger.error(f"Error retrieving order {order_id}: {e}")
        raise


def get_s3_object(s3_key):
    """Retrieve an object from S3 with path validation."""
    validated_key = _validate_s3_key(s3_key)
    
    s3_client = _get_s3_client()
    try:
        response = s3_client.get_object(
            Bucket=S3_DATA_BUCKET,
            Key=validated_key
        )
        return response['Body'].read().decode('utf-8')
    except ClientError as e:
        if e.response['Error']['Code'] == 'NoSuchKey':
            logger.warning(f"S3 object not found: {validated_key}")
            return None
        logger.error(f"Error retrieving S3 object {validated_key}: {e}")
        raise


def lambda_handler(event, context):
    """
    Main Lambda handler that routes requests based on the action field.
    Supports API Gateway, SQS, and direct invocation patterns.
    """
    logger.info(f"Lambda invoked with request ID: {context.aws_request_id}")

    # Check for missing environment variables
    if _missing_vars:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Service misconfiguration'})
        }

    try:
        # Handle API Gateway proxy integration
        if 'httpMethod' in event:
            return _handle_api_gateway_event(event, context)
        
        # Handle SQS trigger
        if 'Records' in event and event['Records'][0].get('eventSource') == 'aws:sqs':
            return _handle_sqs_event(event, context)
        
        # Handle direct invocation
        if 'action' in event:
            return _handle_direct_invocation(event, context)
        
        logger.warning("Unrecognized event format")
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Unrecognized event format'})
        }

    except ValueError as e:
        logger.warning(f"Validation error: {e}")
        return {
            'statusCode': 400,
            'headers': _get_response_headers(),
            'body': json.dumps({'error': str(e)})
        }
    except ClientError as e:
        logger.error(f"AWS service error: {e}")
        return {
            'statusCode': 502,
            'headers': _get_response_headers(),
            'body': json.dumps({'error': 'Service temporarily unavailable'})
        }
    except Exception as e:
        logger.error(f"Unexpected error: {e}", exc_info=True)
        # Do not leak internal error details to the caller
        return {
            'statusCode': 500,
            'headers': _get_response_headers(),
            'body': json.dumps({'error': 'Internal server error'})
        }


def _get_response_headers():
    """Return standard security headers for API Gateway responses."""
    return {
        'Content-Type': 'application/json',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'Cache-Control': 'no-store',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains'
    }


def _handle_api_gateway_event(event, context):
    """Handle API Gateway proxy integration events."""
    http_method = event.get('httpMethod', '')
    path = event.get('path', '')
    
    headers = _get_response_headers()

    if http_method == 'POST' and path == '/orders':
        body = event.get('body', '{}')
        if isinstance(body, str):
            try:
                order_data = json.loads(body)
            except json.JSONDecodeError:
                return {
                    'statusCode': 400,
                    'headers': headers,
                    'body': json.dumps({'error': 'Invalid JSON in request body'})
                }
        else:
            order_data = body

        result = process_order(order_data)
        return {
            'statusCode': 201,
            'headers': headers,
            'body': json.dumps(result)
        }

    elif http_method == 'GET' and path.startswith('/orders/'):
        order_id = path.split('/orders/')[-1].strip('/')
        if not order_id:
            return {
                'statusCode': 400,
                'headers': headers,
                'body': json.dumps({'error': 'Order ID is required'})
            }
        
        order = get_order(order_id)
        if order is None:
            return {
                'statusCode': 404,
                'headers': headers,
                'body': json.dumps({'error': 'Order not found'})
            }
        return {
            'statusCode': 200,
            'headers': headers,
            'body': json.dumps(order, default=str)
        }

    return {
        'statusCode': 404,
        'headers': headers,
        'body': json.dumps({'error': 'Not found'})
    }


def _handle_sqs_event(event, context):
    """Handle SQS trigger events with per-message error handling."""
    failed_message_ids = []
    
    for record in event.get('Records', []):
        message_id = record.get('messageId', 'unknown')
        try:
            body = json.loads(record.get('body', '{}'))
            action = body.get('action', '')
            
            if action == 'PROCESS_ORDER':
                order_id = _sanitize_input(body.get('order_id', ''), 'order_id')
                logger.info(f"Processing order from SQS: {order_id}")
                # Add order processing logic here
            else:
                logger.warning(f"Unknown SQS action: {action} for message {message_id}")
                
        except (json.JSONDecodeError, ValueError) as e:
            logger.error(f"Error processing SQS message {message_id}: {e}")
            failed_message_ids.append(message_id)
        except Exception as e:
            logger.error(f"Unexpected error processing SQS message {message_id}: {e}")
            failed_message_ids.append(message_id)

    # Return partial batch failure response for SQS
    if failed_message_ids:
        return {
            'batchItemFailures': [
                {'itemIdentifier': msg_id} for msg_id in failed_message_ids
            ]
        }
    
    return {'batchItemFailures': []}


def _handle_direct_invocation(event, context):
    """Handle direct Lambda invocation events."""
    action = event.get('action', '')
    
    if action == 'process_order':
        order_data = event.get('order_data', {})
        return process_order(order_data)
    
    elif action == 'get_order':
        order_id = event.get('order_id', '')
        order = get_order(order_id)
        if order is None:
            return {'error': 'Order not found'}
        return order
    
    elif action == 'get_s3_object':
        s3_key = event.get('s3_key', '')
        content = get_s3_object(s3_key)
        if content is None:
            return {'error': 'Object not found'}
        return {'content': content}
    
    else:
        raise ValueError(f"Unknown action: {action}")